examples.code:
// Brightness control, 1–100 with step of 5
<Slider
  label="Brightness"
  value={brightness}
  onValueChange={setBrightness}
  minimumValue={1}
  maximumValue={100}
  step={5}
  showValue
/>

// Disabled slider for read-only display
<Slider
  label="Battery level"
  value={batteryLevel}
  onValueChange={() => {}}
  disabled
/>

// Compact slider without label for inline use
<Slider
  value={opacity}
  onValueChange={setOpacity}
  minimumValue={0}
  maximumValue={1}
  step={0.01}
/>
